        }

        return $headers;
    }

public function map(Builder $builder, $results, $model)
    {
        $results = $results['results'];

        if (count($results) === 0) {
            return $model->newCollection();
        }

        $objectIds = collect($results)
            ->pluck($model->getScoutKeyName())
            ->values()
            ->all();

        $objectIdPositions = array_flip($objectIds);

        return $model->getScoutModelsByIds($builder, $objectIds)
            ->filter(fn ($model) => in_array($model->getScoutKey(), $objectIds))
            ->sortBy(fn ($model) => $objectIdPositions[$model->getScoutKey()])
            ->values();
    }

public function getCustomBlocks(): ?array
    {
        if (blank($this->customBlocks)) {
            return null;
        }

        $blocks = [];

        foreach ($this->customBlocks as $key => $block) {
            if (is_string($key) && is_a($key, RichContentCustomBlock::class, allow_string: true)) {
                // Data association: `BlockClass::class => $data`
                $blocks[] = $key;
            } elseif (is_array($block)) {
                // Group or ungrouped section: `'Label' => [...]` or `[...]`
                foreach ($block as $innerKey => $innerValue) {
                    $blocks[] = is_string($innerKey) ? $innerKey : $innerValue;
                }
            } else {
                $blocks[] = $block;
            }
        }

        return $blocks;
    }

public function resolveRelativeKey(string | Component $key = '', bool $isAbsolute = false): string
    {
        if ($key instanceof Component) {
            return $key->getKey();
        }

        if (str($key)->startsWith('/')) {
            $isAbsolute = true;
            $key = (string) str($key)->after('/');
        }

        if ($isAbsolute) {
            return $key;
        }

        $containerKey = $this->getContainer()->getKey();

        while (str($key)->startsWith('../')) {
            $containerKey = Str::contains($containerKey, '.') ?
                (string) str($containerKey)->beforeLast('.') :
                null;

            $key = (string) str($key)->after('../');
        }

        if (blank($containerKey)) {
            return $key;
        }

        return filled(ltrim($key, './')) ? "{$containerKey}.{$key}" : $containerKey;
    }

protected function mapTableColumnToArray(Column $column): array
    {
        $label = e($column->getLabel());

        if (blank($label) && $this->hasReorderableTableColumns()) {
            throw new LogicException("The table column [{$column->getName()}] has a blank label. All columns must have labels when they are reorderable.");
        }

        return [
            'type' => self::TABLE_COLUMN_MANAGER_COLUMN_TYPE,
            'name' => $column->getName(),
            'label' => $label,
            'isHidden' => $column->isHidden(),
            'isToggled' => ! $column->isToggleable() || ! $column->isToggledHiddenByDefault(),
            'isToggleable' => $column->isToggleable(),
            'isToggledHiddenByDefault' => $column->isToggleable() ? $column->isToggledHiddenByDefault() : null,
        ];
    }

public function off(string $name, callable $callback): void
    {
        if (isset($this->listeners[$name])) {
            $index = array_search($callback, $this->listeners[$name], true);

            if ($index !== false) {
                unset($this->listeners[$name][$index]);
                return;
            }
        }

        if (isset($this->listenersAfter[$name])) {
            $index = array_search($callback, $this->listenersAfter[$name], true);

            if ($index !== false) {
                unset($this->listenersAfter[$name][$index]);
                return;
            }
        }

        if (isset($this->listenersBefore[$name])) {
            $index = array_search($callback, $this->listenersBefore[$name], true);

            if ($index !== false) {
                unset($this->listenersBefore[$name][$index]);
            }
        }
    }

function __call($method, $params)
    {
        $value = 'noneset';

        $returnValue = function ($newValue) use (&$value) {
            $value = $newValue;
        };

        $finish = trigger('__call', $this, $method, $params, $returnValue);

        $value = $finish($value);

        if ($value !== 'noneset') {
            return $value;
        }

        if (static::hasMacro($method)) {
            return $this->macroCall($method, $params);
        }

        throw new BadMethodCallException(sprintf(
            'Method %s::%s does not exist.', static::class, $method
        ));
    }

